output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?consoleLabel ?cpuLabel ?storageValue ?memoryValue ?gpuLabel ?backwardcompatLabel WHERE {
  ?console wdt:P361 wd:Q70213529 ; rdfs:label ?consoleLabel ; wdt:P5342 ?soc ; wdt:P1224 ?storageValue ; wdt:P2550 ?memoryValue ; wdt:P3060 ?backwardcompat .
  ?soc wdt:P880 ?cpu ; wdt:P2560 ?gpu .
  FILTER(LANG(?consoleLabel) = "en")
  OPTIONAL {
    ?cpu rdfs:label ?cpuLabel .
    FILTER(LANG(?cpuLabel) = "en")
  }
  OPTIONAL {
    ?gpu rdfs:label ?gpuLabel .
    FILTER(LANG(?gpuLabel) = "en")
  }
  OPTIONAL {
    ?backwardcompat rdfs:label ?backwardcompatLabel .
    FILTER(LANG(?backwardcompatLabel) = "en")
  }
}

